<template>
  <div class="home">
    <!-- 左侧操作区 -->
    <div class="left">
      <div class="section">
        <h3>1. 上传Excel文件</h3>
        <!-- 主数据上传 -->
        <div class="upload-item">
          <label>主数据Excel：</label>
          <el-upload
            ref="mainUploadRef"
            :auto-upload="false"
            :limit="1"
            accept=".xlsx,.xls"
            :on-change="handleMainFileChange"
            :on-exceed="handleExceedMain"
          >
            <el-button type="primary" size="small">选择文件</el-button>
            <template #tip>
              <div class="el-upload__tip">仅支持 .xlsx / .xls 格式，单文件上传</div>
            </template>
          </el-upload>
          <div v-if="mainFileName" class="file-name">已选择：{{ mainFileName }}</div>
        </div>

        <!-- 次数据上传 -->
        <div class="upload-item">
          <label>次数据Excel（支持多文件，点击切换配置）：</label>
          <el-upload
            ref="subUploadRef"
            :auto-upload="false"
            :limit="10"
            accept=".xlsx,.xls"
            :show-file-list="false"
            :on-change="handleSubFileChange"
            :on-exceed="handleExceed"
            multiple
          >
            <el-button type="primary" size="small">选择文件</el-button>
            <template #tip>
              <div class="el-upload__tip">支持 .xlsx / .xls 格式，最多10个文件</div>
            </template>
          </el-upload>
          <div v-if="subFileList.length > 0" class="file-list">
            已上传次文件（点击选中配置）：
            <div
              v-for="(file, index) in subFileList"
              :key="index"
              class="file-item"
              :class="{ active: currentSubIndex === index }"
              @click="selectSubFile(index)"
            >
              <span>{{ file.name }}</span>
              <el-button type="danger" size="mini" @click.stop="removeSubFile(index)">删除</el-button>
            </div>
          </div>
          <div v-if="currentSubIndex === null && subFileList.length" class="tip-text">
            请点击上方任意次文件进行配置
          </div>
        </div>
      </div>

      <div class="section">
        <h3>2. 选择处理功能</h3>
        <el-select
          v-model="selectedFunction"
          placeholder="请选择处理功能"
          style="width: 100%"
          :disabled="!mainData.length || !subFileList.length"
        >
          <el-option label="主数据中存在于次数据的数据（全部次文件匹配）" value="1" />
          <el-option label="主数据中不存在于次数据的数据（全部次文件匹配）" value="2" />
          <el-option label="全部次数据指定列依次拼接到主数据后" value="3" />
        </el-select>
      </div>

      <div class="section" v-if="currentSubIndex !== null">
        <h3>3. 当前次文件：{{ currentSubFile.name }} 配置</h3>
        <div class="config-item">
          <label>主数据对比列：</label>
          <el-select
            v-model="currentConfig.mainCompareCol"
            placeholder="请选择主数据对比列"
            style="width: 100%"
          >
            <el-option
              v-for="column in mainColumns"
              :key="column"
              :label="column"
              :value="column"
            />
          </el-select>
        </div>
        <div class="config-item">
          <label>本次文件对比列：</label>
          <el-select
            v-model="currentConfig.subCompareCol"
            placeholder="请选择次数据对比列"
            style="width: 100%"
          >
            <el-option
              v-for="column in currentSubColumns"
              :key="column"
              :label="column"
              :value="column"
            />
          </el-select>
        </div>

        <!-- 功能3专属配置：选择要拼接的列 -->
        <div class="config-item" v-if="selectedFunction === '3'">
          <label>本次文件需要拼接的列（多选）：</label>
          <el-select
            v-model="currentConfig.mergeCols"
            placeholder="请选择要拼接的列"
            multiple
            style="width: 100%"
          >
            <el-option
              v-for="column in currentSubColumns"
              :key="column"
              :label="column"
              :value="column"
            />
          </el-select>
        </div>
      </div>

      <div class="section">
        <h3>4. 操作</h3>
        <div class="action-buttons">
          <el-button
            type="success"
            size="large"
            @click="handlePreview"
            :disabled="!isConfigValid"
            :loading="isProcessing"
          >
            预览结果
          </el-button>
          <el-button
            type="primary"
            size="large"
            @click="handleExport"
            :disabled="!processedData.length"
            :loading="isProcessing"
          >
            导出Excel
          </el-button>
        </div>
      </div>
    </div>

    <!-- 右侧预览区 -->
    <div class="right">
      <div class="preview-header">
        <h3>处理结果预览</h3>
        <span v-if="processedData.length > 0" class="data-count">共 {{ processedData.length }} 条数据</span>
      </div>
      <!-- 隔离容器解决ResizeObserver报错 -->
      <div class="preview-content">
        <div style="width:100%;height:100%;overflow:auto;">
          <el-table
            v-if="processedData.length > 0"
            :data="processedData"
            border
            stripe
            style="width: 100%"
            max-height="calc(100vh - 120px)"
          >
            <el-table-column
              v-for="column in processedColumns"
              :key="column"
              :prop="column"
              :label="column"
              min-width="120"
              show-overflow-tooltip
            />
          </el-table>
          <div v-else class="empty-preview">
            <el-empty description="暂无预览数据，请先完成配置并点击预览" />
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'
import * as XLSX from 'xlsx'
import { ElMessage, ElUpload } from 'element-plus'

// 上传ref
const mainUploadRef = ref(null)
const subUploadRef = ref(null)

// 主数据
const mainFileName = ref('')
const mainColumns = ref([])
const mainData = ref([])

// 次文件结构：每个文件携带独立配置
// { name, columns, data, config:{ mainCompareCol, subCompareCol, mergeCols:[] } }
const subFileList = ref([])
const currentSubIndex = ref(null)

// 当前选中次文件快捷取值
const currentSubFile = computed(() => {
  if (currentSubIndex.value === null) return null
  return subFileList.value[currentSubIndex.value]
})
const currentSubColumns = computed(() => currentSubFile.value?.columns || [])
const currentConfig = computed(() => {
  if (!currentSubFile.value) return { mainCompareCol: '', subCompareCol: '', mergeCols: [] }
  return currentSubFile.value.config
})

// 功能、结果
const selectedFunction = ref('')
const processedData = ref([])
const processedColumns = ref([])
const isProcessing = ref(false)

// 校验：所有次文件必须填好对应配置
const isConfigValid = computed(() => {
  if (!mainData.value.length || !subFileList.value.length || !selectedFunction.value) return false
  for (const file of subFileList.value) {
    const cfg = file.config
    if (!cfg.mainCompareCol || !cfg.subCompareCol) return false
    if (selectedFunction.value === '3' && !cfg.mergeCols.length) return false
  }
  return true
})

// 主文件上传
const handleMainFileChange = (file) => {
  const rawFile = file.raw
  if (!rawFile) return
  mainFileName.value = file.name
  parseExcelFile(rawFile, (columns, data) => {
    mainColumns.value = columns
    mainData.value = data
    // 清空结果
    processedData.value = []
    processedColumns.value = []
    ElMessage.success('主数据解析成功')
  })
}

// 次文件上传，附带独立配置对象
const handleSubFileChange = (file) => {
  const rawFile = file.raw
  if (!rawFile) return
  const exists = subFileList.value.some(item => item.name === file.name)
  if (exists) {
    ElMessage.warning('该文件已上传')
    return
  }
  parseExcelFile(rawFile, (columns, data) => {
    subFileList.value.push({
      name: file.name,
      columns,
      data,
      // 每个文件独立配置
      config: {
        mainCompareCol: '',
        subCompareCol: '',
        mergeCols: []
      }
    })
    // 自动选中第一个
    if (subFileList.value.length === 1) {
      selectSubFile(0)
    }
    processedData.value = []
    processedColumns.value = []
    ElMessage.success(`次文件 ${file.name} 解析成功`)
  })
}

// 切换选中次文件
const selectSubFile = (index) => {
  currentSubIndex.value = index
  processedData.value = []
  processedColumns.value = []
}

// 删除次文件
const removeSubFile = (index) => {
  subFileList.value.splice(index, 1)
  if (!subFileList.value.length) {
    currentSubIndex.value = null
  } else if (currentSubIndex.value === index) {
    selectSubFile(0)
  }
  ElMessage.success('文件已删除')
}

const handleExceedMain = () => ElMessage.warning('最多上传1个主文件')
const handleExceed = () => ElMessage.warning('最多上传10个次文件')

// 解析Excel通用
const parseExcelFile = (file, callback) => {
  const reader = new FileReader()
  reader.onload = e => {
    try {
      const arr = new Uint8Array(e.target.result)
      const wb = XLSX.read(arr, { type: 'array' })
      const sheet = wb.Sheets[wb.SheetNames[0]]
      const json = XLSX.utils.sheet_to_json(sheet)
      if (!json.length) return ElMessage.error('表格无数据')
      callback(Object.keys(json[0]), json)
    } catch (err) {
      ElMessage.error('解析Excel失败')
      console.error(err)
    }
  }
  reader.readAsArrayBuffer(file)
}

// 核心多文件处理逻辑
const processData = () => {
  const mainSource = [...mainData.value]
  let result = []
  let resultCols = [...mainColumns.value]

  switch (selectedFunction.value) {
    case '1': {
      // 存在于任意次文件的数据
      const allSubMatchValues = new Set()
      subFileList.value.forEach(file => {
        const cfg = file.config
        file.data.forEach(row => allSubMatchValues.add(String(row[cfg.subCompareCol])))
      })
      // 随便取第一个文件的主对比列（所有文件主对比列配置必须一致）
      const firstCfg = subFileList.value[0].config
      result = mainSource.filter(r => allSubMatchValues.has(String(r[firstCfg.mainCompareCol])))
      break
    }
    case '2': {
      // 不在任何次文件的数据
      const allSubMatchValues = new Set()
      subFileList.value.forEach(file => {
        const cfg = file.config
        file.data.forEach(row => allSubMatchValues.add(String(row[cfg.subCompareCol])))
      })
      const firstCfg = subFileList.value[0].config
      result = mainSource.filter(r => !allSubMatchValues.has(String(r[firstCfg.mainCompareCol])))
      break
    }
    case '3': {
      // 多文件依次拼接
      let tempData = JSON.parse(JSON.stringify(mainSource))
      // 遍历每一个次文件，逐个拼接字段
      subFileList.value.forEach(file => {
        const { config: cfg, data: subRows } = file
        // 构建当前次文件映射
        const map = new Map()
        subRows.forEach(r => map.set(String(r[cfg.subCompareCol]), r))
        // 每行匹配追加字段
        tempData = tempData.map(mainRow => {
          const key = String(mainRow[cfg.mainCompareCol])
          const matchSub = map.get(key) || {}
          const appendFields = {}
          cfg.mergeCols.forEach(col => appendFields[col] = matchSub[col])
          return { ...mainRow, ...appendFields }
        })
        // 列追加
        resultCols.push(...cfg.mergeCols)
      })
      result = tempData
      break
    }
  }
  return { result, resultColumns: resultCols }
}

// 预览
const handlePreview = () => {
  if (!isConfigValid.value) return ElMessage.warning('请完成所有次文件的配置')
  isProcessing.value = true
  setTimeout(() => {
    const { result, resultColumns } = processData()
    processedData.value = result
    processedColumns.value = resultColumns
    isProcessing.value = false
    ElMessage.success(`处理完成，共${result.length}条数据`)
  }, 100)
}

// 导出
const handleExport = () => {
  if (!processedData.value.length) return ElMessage.warning('无数据导出')
  isProcessing.value = true
  setTimeout(() => {
    try {
      const wb = XLSX.utils.book_new()
      const ws = XLSX.utils.json_to_sheet(processedData.value, { header: processedColumns.value })
      XLSX.utils.book_append_sheet(wb, ws, '处理结果')
      XLSX.writeFile(wb, `多表合并结果_${Date.now()}.xlsx`)
      ElMessage.success('导出成功')
    } catch (err) {
      ElMessage.error('导出失败')
      console.error(err)
    } finally {
      isProcessing.value = false
    }
  }, 100)
}
</script>

